21	export function resolveIrcInboundTarget(params: { target: string; senderNick: string }): {
22	  isGroup: boolean;
23	  target: string;
24	  rawTarget: string;
25	} {
26	  const rawTarget = params.target;
27	  const isGroup = isChannelTarget(rawTarget);
28	  if (isGroup) {
29	    return { isGroup: true, target: rawTarget, rawTarget };
