  allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
  groupPolicy: GroupPolicySchema.optional().default("allowlist"),
  groups: z.record(z.string(), IrcGroupSchema.optional()).optional(),
  channels: z.array(z.string()).optional(),
  // ... more fields
}).strict();

export const IrcChannelConfigSchema = buildChannelConfigSchema(
  IrcConfigSchema,
  { uiHints: ircChannelConfigUiHints }
);
```

**Key patterns**:
- `.strict()` prevents unknown properties
- `.superRefine()` for complex validation (e.g., NickServ email required when register=true)
- `buildChannelConfigSchema` extends with standard channel fields

