71	  defaultAccount?: string;
72	};
73	
74	export type CoreConfig = OpenClawConfig & {
75	  channels?: OpenClawConfig["channels"] & {
76	    irc?: IrcConfig;
77	  };
78	};
79	
80	export type IrcInboundMessage = {
81	  messageId: string;
82	  /** Conversation peer id: channel name for groups, sender nick for DMs. */
83	  target: string;
84	  /** Raw IRC PRIVMSG target (bot nick for DMs, channel for groups). */
85	  rawTarget?: string;
86	  senderNick: string;
87	  senderUser?: string;
88	  senderHost?: string;
89	  text: string;
90	  timestamp: number;
91	  isGroup: boolean;
92	};
93	
94	export type IrcProbe = BaseProbeResult<string> & {
95	  host: string;
96	  port: number;
97	  tls: boolean;
