121	/** Fast-path DM command authorization when only policy and sender allowlist state matter. */
122	export function resolveDirectDmAuthorizationOutcome(params: {
123	  isGroup: boolean;
124	  dmPolicy: string;
125	  senderAllowedForCommands: boolean;
126	}): "disabled" | "unauthorized" | "allowed" {
127	  if (params.isGroup) {
128	    return "allowed";
129	  }
130	  if (params.dmPolicy === "disabled") {
131	    return "disabled";
132	  }
133	  if (params.dmPolicy !== "open" && !params.senderAllowedForCommands) {
134	    return "unauthorized";
135	  }
136	  return "allowed";
137	}
