139	/** Runtime-backed wrapper around sender command authorization for grouped helper surfaces. */
140	export async function resolveSenderCommandAuthorizationWithRuntime(
141	  params: ResolveSenderCommandAuthorizationWithRuntimeParams,
142	): ReturnType<typeof resolveSenderCommandAuthorization> {
143	  return resolveSenderCommandAuthorization({
144	    ...params,
145	    shouldComputeCommandAuthorized: params.runtime.shouldComputeCommandAuthorized,
146	    resolveCommandAuthorizedFromAuthorizers: params.runtime.resolveCommandAuthorizedFromAuthorizers,
147	  });
148	}
149	
150	/** Compute effective allowlists and command authorization for one inbound sender. */
151	export async function resolveSenderCommandAuthorization(
152	  params: ResolveSenderCommandAuthorizationParams,
153	): Promise<{
154	  shouldComputeAuth: boolean;
155	  effectiveAllowFrom: string[];
156	  effectiveGroupAllowFrom: string[];
157	  senderAllowedForCommands: boolean;
158	  commandAuthorized: boolean | undefined;
159	}> {
160	  const shouldComputeAuth = params.shouldComputeCommandAuthorized(params.rawBody, params.cfg);
161	  const storeAllowFrom =
162	    !params.isGroup &&
163	    params.dmPolicy !== "allowlist" &&
164	    (params.dmPolicy !== "open" || shouldComputeAuth)
165	      ? await params.readAllowFromStore().catch(() => [])
166	      : [];
167	  const access = resolveDmGroupAccessWithLists({
168	    isGroup: params.isGroup,
169	    dmPolicy: params.dmPolicy,
170	    groupPolicy: "allowlist",
171	    allowFrom: params.configuredAllowFrom,
172	    groupAllowFrom: params.configuredGroupAllowFrom ?? [],
173	    storeAllowFrom,
174	    isSenderAllowed: (allowFrom) => params.isSenderAllowed(params.senderId, allowFrom),
175	  });
176	  const effectiveAllowFrom = access.effectiveAllowFrom;
177	  const effectiveGroupAllowFrom = access.effectiveGroupAllowFrom;
178	  const useAccessGroups = params.cfg.commands?.useAccessGroups !== false;
179	  const senderAllowedForCommands = params.isSenderAllowed(
180	    params.senderId,
181	    params.isGroup ? effectiveGroupAllowFrom : effectiveAllowFrom,
182	  );
183	  const ownerAllowedForCommands = params.isSenderAllowed(params.senderId, effectiveAllowFrom);
184	  const groupAllowedForCommands = params.isSenderAllowed(params.senderId, effectiveGroupAllowFrom);
185	  const commandAuthorized = shouldComputeAuth
186	    ? params.resolveCommandAuthorizedFromAuthorizers({
187	        useAccessGroups,
188	        authorizers: [
189	          { configured: effectiveAllowFrom.length > 0, allowed: ownerAllowedForCommands },
190	          { configured: effectiveGroupAllowFrom.length > 0, allowed: groupAllowedForCommands },
191	        ],
192	      })
193	    : undefined;
194	
195	  return {
196	    shouldComputeAuth,
197	    effectiveAllowFrom,
198	    effectiveGroupAllowFrom,
199	    senderAllowedForCommands,
200	    commandAuthorized,
201	  };
202	}
