6	import type { ReplyDispatcher } from "../auto-reply/reply/reply-dispatcher.js";
7	import type { FinalizedMsgContext } from "../auto-reply/templating.js";
8	import type { GetReplyOptions } from "../auto-reply/types.js";
9	import type { OpenClawConfig } from "../config/config.js";
10	import { createChannelReplyPipeline } from "./channel-reply-pipeline.js";
11	import { createNormalizedOutboundDeliverer, type OutboundReplyPayload } from "./reply-payload.js";
12	
13	type ReplyOptionsWithoutModelSelected = Omit<
14	  Omit<GetReplyOptions, "onToolResult" | "onBlockReply">,
15	  "onModelSelected"
16	>;
17	type RecordInboundSessionFn = typeof import("../channels/session.js").recordInboundSession;
18	type DispatchReplyWithBufferedBlockDispatcherFn =
19	  typeof import("../auto-reply/reply/provider-dispatcher.js").dispatchReplyWithBufferedBlockDispatcher;
20	
21	type ReplyDispatchFromConfigOptions = Omit<GetReplyOptions, "onToolResult" | "onBlockReply">;
22	
23	/** Run `dispatchReplyFromConfig` with a dispatcher that always gets its settled callback. */
24	export async function dispatchReplyFromConfigWithSettledDispatcher(params: {
25	  cfg: OpenClawConfig;
26	  ctxPayload: FinalizedMsgContext;
27	  dispatcher: ReplyDispatcher;
28	  onSettled: () => void | Promise<void>;
29	  replyOptions?: ReplyDispatchFromConfigOptions;
30	  configOverride?: OpenClawConfig;
31	}): Promise<DispatchFromConfigResult> {
32	  return await withReplyDispatcher({
33	    dispatcher: params.dispatcher,
34	    onSettled: params.onSettled,
35	    run: () =>
36	      dispatchReplyFromConfig({
37	        ctx: params.ctxPayload,
38	        cfg: params.cfg,
39	        dispatcher: params.dispatcher,
40	        replyOptions: params.replyOptions,
41	        configOverride: params.configOverride,
42	      }),
43	  });
44	}
45	
46	/** Assemble the common inbound reply dispatch dependencies for a resolved route. */
47	export function buildInboundReplyDispatchBase(params: {
48	  cfg: OpenClawConfig;
49	  channel: string;
50	  accountId?: string;
51	  route: {
52	    agentId: string;
53	    sessionKey: string;
54	  };
55	  storePath: string;
56	  ctxPayload: FinalizedMsgContext;
57	  core: {
58	    channel: {
59	      session: {
60	        recordInboundSession: RecordInboundSessionFn;
61	      };
62	      reply: {
63	        dispatchReplyWithBufferedBlockDispatcher: DispatchReplyWithBufferedBlockDispatcherFn;
64	      };
65	    };
66	  };
67	}) {
68	  return {
69	    cfg: params.cfg,
70	    channel: params.channel,
71	    accountId: params.accountId,
72	    agentId: params.route.agentId,
73	    routeSessionKey: params.route.sessionKey,
74	    storePath: params.storePath,
75	    ctxPayload: params.ctxPayload,
76	    recordInboundSession: params.core.channel.session.recordInboundSession,
77	    dispatchReplyWithBufferedBlockDispatcher:
78	      params.core.channel.reply.dispatchReplyWithBufferedBlockDispatcher,
79	  };
80	}
81	
82	type BuildInboundReplyDispatchBaseParams = Parameters<typeof buildInboundReplyDispatchBase>[0];
83	type RecordInboundSessionAndDispatchReplyParams = Parameters<
84	  typeof recordInboundSessionAndDispatchReply
85	>[0];
86	
87	/** Resolve the shared dispatch base and immediately record + dispatch one inbound reply turn. */
88	export async function dispatchInboundReplyWithBase(
89	  params: BuildInboundReplyDispatchBaseParams &
90	    Pick<
91	      RecordInboundSessionAndDispatchReplyParams,
92	      "deliver" | "onRecordError" | "onDispatchError" | "replyOptions"
93	    >,
94	): Promise<void> {
95	  const dispatchBase = buildInboundReplyDispatchBase(params);
96	  await recordInboundSessionAndDispatchReply({
97	    ...dispatchBase,
98	    deliver: params.deliver,
99	    onRecordError: params.onRecordError,
100	    onDispatchError: params.onDispatchError,
101	    replyOptions: params.replyOptions,
102	  });
103	}
104	
105	/** Record the inbound session first, then dispatch the reply using normalized outbound delivery. */
106	export async function recordInboundSessionAndDispatchReply(params: {
107	  cfg: OpenClawConfig;
108	  channel: string;
109	  accountId?: string;
110	  agentId: string;
111	  routeSessionKey: string;
112	  storePath: string;
113	  ctxPayload: FinalizedMsgContext;
114	  recordInboundSession: RecordInboundSessionFn;
115	  dispatchReplyWithBufferedBlockDispatcher: DispatchReplyWithBufferedBlockDispatcherFn;
116	  deliver: (payload: OutboundReplyPayload) => Promise<void>;
117	  onRecordError: (err: unknown) => void;
118	  onDispatchError: (err: unknown, info: { kind: string }) => void;
119	  replyOptions?: ReplyOptionsWithoutModelSelected;
120	}): Promise<void> {
121	  await params.recordInboundSession({
