34	function parseListInput(raw: string): string[] {
35	  return raw
36	    .split(/[\n,;]+/g)
37	    .map((entry) => entry.trim())
38	    .filter(Boolean);
39	}
40	
41	function normalizeGroupEntry(raw: string): string | null {
42	  const trimmed = raw.trim();
43	  if (!trimmed) {
44	    return null;
45	  }
46	  if (trimmed === "*") {
47	    return "*";
48	  }
49	  const normalized = normalizeIrcMessagingTarget(trimmed) ?? trimmed;
50	  if (isChannelTarget(normalized)) {
51	    return normalized;
52	  }
53	  return `#${normalized.replace(/^#+/, "")}`;
54	}
55	
56	const promptIrcAllowFrom = createPromptParsedAllowFromForAccount<CoreConfig>({
57	  defaultAccountId: (cfg) => resolveDefaultIrcAccountId(cfg),
58	  noteTitle: "IRC allowlist",
59	  noteLines: [
60	    "Allowlist IRC DMs by sender.",
61	    "Examples:",
62	    "- alice",
63	    "- alice!ident@example.org",
64	    "Multiple entries: comma-separated.",
65	  ],
66	  message: "IRC allowFrom (nick or nick!user@host)",
67	  placeholder: "alice, bob!ident@example.org",
68	  parseEntries: (raw) => ({
69	    entries: parseListInput(raw)
70	      .map((entry) => normalizeIrcAllowEntry(entry))
71	      .map((entry) => entry.trim())
72	      .filter(Boolean),
73	  }),
74	  getExistingAllowFrom: ({ cfg }) => cfg.channels?.irc?.allowFrom ?? [],
75	  applyAllowFrom: ({ cfg, allowFrom }) => setIrcAllowFrom(cfg, allowFrom),
76	});
77	
78	async function promptIrcNickServConfig(params: {
79	  cfg: CoreConfig;
80	  prompter: WizardPrompter;
81	  accountId: string;
82	}): Promise<CoreConfig> {
83	  const resolved = resolveIrcAccount({ cfg: params.cfg, accountId: params.accountId });
84	  const existing = resolved.config.nickserv;
85	  const hasExisting = Boolean(existing?.password || existing?.passwordFile);
86	  const wants = await params.prompter.confirm({
87	    message: hasExisting ? "Update NickServ settings?" : "Configure NickServ identify/register?",
88	    initialValue: hasExisting,
89	  });
90	  if (!wants) {
91	    return params.cfg;
92	  }
93	
94	  const service = String(
95	    await params.prompter.text({
96	      message: "NickServ service nick",
97	      initialValue: existing?.service || "NickServ",
98	      validate: (value) => (String(value ?? "").trim() ? undefined : "Required"),
99	    }),
100	  ).trim();
101	
102	  const useEnvPassword =
103	    params.accountId === DEFAULT_ACCOUNT_ID &&
104	    Boolean(process.env.IRC_NICKSERV_PASSWORD?.trim()) &&
105	    !(existing?.password || existing?.passwordFile)
106	      ? await params.prompter.confirm({
107	          message: "IRC_NICKSERV_PASSWORD detected. Use env var?",
108	          initialValue: true,
109	        })
110	      : false;
111	
112	  const password = useEnvPassword
113	    ? undefined
114	    : String(
115	        await params.prompter.text({
116	          message: "NickServ password (blank to disable NickServ auth)",
117	          validate: () => undefined,
118	        }),
119	      ).trim();
120	
121	  if (!password && !useEnvPassword) {
122	    return setIrcNickServ(params.cfg, params.accountId, {
123	      enabled: false,
124	      service,
125	    });
126	  }
127	
128	  const register = await params.prompter.confirm({
129	    message: "Send NickServ REGISTER on connect?",
130	    initialValue: existing?.register ?? false,
131	  });
132	  const registerEmail = register
133	    ? String(
134	        await params.prompter.text({
135	          message: "NickServ register email",
136	          initialValue:
137	            existing?.registerEmail ||
138	            (params.accountId === DEFAULT_ACCOUNT_ID
139	              ? process.env.IRC_NICKSERV_REGISTER_EMAIL
140	              : undefined),
141	          validate: (value) => (String(value ?? "").trim() ? undefined : "Required"),
142	        }),
143	      ).trim()
144	    : undefined;
145	
146	  return setIrcNickServ(params.cfg, params.accountId, {
147	    enabled: true,
148	    service,
149	    ...(password ? { password } : {}),
150	    register,
151	    ...(registerEmail ? { registerEmail } : {}),
152	  });
153	}
154	
155	const ircDmPolicy: ChannelSetupDmPolicy = {
156	  label: "IRC",
157	  channel,
158	  policyKey: "channels.irc.dmPolicy",
159	  allowFromKey: "channels.irc.allowFrom",
160	  getCurrent: (cfg) => (cfg as CoreConfig).channels?.irc?.dmPolicy ?? "pairing",
161	  setPolicy: (cfg, policy) => setIrcDmPolicy(cfg as CoreConfig, policy),
162	  promptAllowFrom: async ({ cfg, prompter, accountId }) =>
163	    await promptIrcAllowFrom({
164	      cfg: cfg as CoreConfig,
165	      prompter,
166	      accountId,
167	    }),
168	};
169	
170	export const ircSetupWizard: ChannelSetupWizard = {
171	  channel,
172	  status: createStandardChannelSetupStatus({
173	    channelLabel: "IRC",
174	    configuredLabel: "configured",
175	    unconfiguredLabel: "needs host + nick",
176	    configuredHint: "configured",
177	    unconfiguredHint: "needs host + nick",
178	    configuredScore: 1,
179	    unconfiguredScore: 0,
180	    includeStatusLine: true,
181	    resolveConfigured: ({ cfg }) =>
182	      listIrcAccountIds(cfg as CoreConfig).some(
183	        (accountId) => resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).configured,
184	      ),
185	  }),
186	  introNote: {
187	    title: "IRC setup",
188	    lines: [
189	      "IRC needs server host + bot nick.",
190	      "Recommended: TLS on port 6697.",
191	      "Optional: NickServ identify/register can be configured after the basic account fields.",
192	      'Set channels.irc.groupPolicy="allowlist" and channels.irc.groups for tighter channel control.',
193	      'Note: IRC channels are mention-gated by default. To allow unmentioned replies, set channels.irc.groups["#channel"].requireMention=false (or "*" for all).',
194	      "Env vars supported: IRC_HOST, IRC_PORT, IRC_TLS, IRC_NICK, IRC_USERNAME, IRC_REALNAME, IRC_PASSWORD, IRC_CHANNELS, IRC_NICKSERV_PASSWORD, IRC_NICKSERV_REGISTER_EMAIL.",
195	      `Docs: ${formatDocsLink("/channels/irc", "channels/irc")}`,
196	    ],
197	    shouldShow: ({ cfg, accountId }) =>
198	      !resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).configured,
199	  },
200	  prepare: async ({ cfg, accountId, credentialValues, prompter }) => {
201	    const resolved = resolveIrcAccount({ cfg: cfg as CoreConfig, accountId });
202	    const isDefaultAccount = accountId === DEFAULT_ACCOUNT_ID;
203	    const envHost = isDefaultAccount ? process.env.IRC_HOST?.trim() : "";
204	    const envNick = isDefaultAccount ? process.env.IRC_NICK?.trim() : "";
205	    const envReady = Boolean(envHost && envNick && !resolved.config.host && !resolved.config.nick);
206	
207	    if (envReady) {
208	      const useEnv = await prompter.confirm({
209	        message: "IRC_HOST and IRC_NICK detected. Use env vars?",
210	        initialValue: true,
211	      });
212	      if (useEnv) {
213	        return {
214	          cfg: updateIrcAccountConfig(cfg as CoreConfig, accountId, { enabled: true }),
215	          credentialValues: {
216	            ...credentialValues,
217	            [USE_ENV_FLAG]: "1",
218	          },
219	        };
220	      }
221	    }
222	
223	    const tls = await prompter.confirm({
224	      message: "Use TLS for IRC?",
225	      initialValue: resolved.config.tls ?? true,
226	    });
227	    return {
228	      cfg: updateIrcAccountConfig(cfg as CoreConfig, accountId, {
229	        enabled: true,
230	        tls,
231	      }),
232	      credentialValues: {
233	        ...credentialValues,
234	        [USE_ENV_FLAG]: "0",
235	        [TLS_FLAG]: tls ? "1" : "0",
236	      },
237	    };
238	  },
239	  credentials: [],
240	  textInputs: [
241	    {
242	      inputKey: "httpHost",
243	      message: "IRC server host",
244	      currentValue: ({ cfg, accountId }) =>
245	        resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).config.host || undefined,
246	      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
247	      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
248	      normalizeValue: ({ value }) => String(value).trim(),
249	      applySet: async ({ cfg, accountId, value }) =>
250	        updateIrcAccountConfig(cfg as CoreConfig, accountId, {
251	          enabled: true,
252	          host: value,
253	        }),
254	    },
255	    {
256	      inputKey: "httpPort",
257	      message: "IRC server port",
258	      currentValue: ({ cfg, accountId }) =>
259	        String(resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).config.port ?? ""),
260	      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
261	      initialValue: ({ cfg, accountId, credentialValues }) => {
262	        const resolved = resolveIrcAccount({ cfg: cfg as CoreConfig, accountId });
263	        const tls = credentialValues[TLS_FLAG] === "0" ? false : true;
264	        const defaultPort = resolved.config.port ?? (tls ? 6697 : 6667);
265	        return String(defaultPort);
266	      },
267	      validate: ({ value }) => {
268	        const parsed = Number.parseInt(String(value ?? "").trim(), 10);
269	        return Number.isFinite(parsed) && parsed >= 1 && parsed <= 65535
270	          ? undefined
271	          : "Use a port between 1 and 65535";
272	      },
273	      normalizeValue: ({ value }) => String(parsePort(String(value), 6697)),
274	      applySet: async ({ cfg, accountId, value }) =>
275	        updateIrcAccountConfig(cfg as CoreConfig, accountId, {
276	          enabled: true,
277	          port: parsePort(String(value), 6697),
278	        }),
279	    },
280	    {
281	      inputKey: "token",
282	      message: "IRC nick",
283	      currentValue: ({ cfg, accountId }) =>
284	        resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).config.nick || undefined,
285	      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
286	      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
287	      normalizeValue: ({ value }) => String(value).trim(),
288	      applySet: async ({ cfg, accountId, value }) =>
289	        updateIrcAccountConfig(cfg as CoreConfig, accountId, {
290	          enabled: true,
291	          nick: value,
292	        }),
293	    },
294	    {
295	      inputKey: "userId",
296	      message: "IRC username",
297	      currentValue: ({ cfg, accountId }) =>
298	        resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).config.username || undefined,
299	      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
300	      initialValue: ({ cfg, accountId, credentialValues }) =>
301	        resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).config.username ||
302	        credentialValues.token ||
303	        "openclaw",
304	      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
305	      normalizeValue: ({ value }) => String(value).trim(),
306	      applySet: async ({ cfg, accountId, value }) =>
307	        updateIrcAccountConfig(cfg as CoreConfig, accountId, {
308	          enabled: true,
309	          username: value,
310	        }),
311	    },
312	    {
313	      inputKey: "deviceName",
314	      message: "IRC real name",
315	      currentValue: ({ cfg, accountId }) =>
316	        resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).config.realname || undefined,
317	      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
318	      initialValue: ({ cfg, accountId }) =>
319	        resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).config.realname || "OpenClaw",
320	      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
321	      normalizeValue: ({ value }) => String(value).trim(),
322	      applySet: async ({ cfg, accountId, value }) =>
323	        updateIrcAccountConfig(cfg as CoreConfig, accountId, {
324	          enabled: true,
325	          realname: value,
326	        }),
327	    },
328	    {
329	      inputKey: "groupChannels",
330	      message: "Auto-join IRC channels (optional, comma-separated)",
331	      placeholder: "#openclaw, #ops",
332	      required: false,
333	      applyEmptyValue: true,
334	      currentValue: ({ cfg, accountId }) =>
335	        resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).config.channels?.join(", "),
336	      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
337	      normalizeValue: ({ value }) =>
338	        parseListInput(String(value))
339	          .map((entry) => normalizeGroupEntry(entry))
340	          .filter((entry): entry is string => Boolean(entry && entry !== "*"))
341	          .filter((entry) => isChannelTarget(entry))
342	          .join(", "),
343	      applySet: async ({ cfg, accountId, value }) => {
344	        const channels = parseListInput(String(value))
345	          .map((entry) => normalizeGroupEntry(entry))
346	          .filter((entry): entry is string => Boolean(entry && entry !== "*"))
347	          .filter((entry) => isChannelTarget(entry));
348	        return updateIrcAccountConfig(cfg as CoreConfig, accountId, {
349	          enabled: true,
350	          channels: channels.length > 0 ? channels : undefined,
351	        });
352	      },
353	    },
354	  ],
355	  groupAccess: {
356	    label: "IRC channels",
357	    placeholder: "#openclaw, #ops, *",
358	    currentPolicy: ({ cfg, accountId }) =>
359	      resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).config.groupPolicy ?? "allowlist",
360	    currentEntries: ({ cfg, accountId }) =>
361	      Object.keys(resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).config.groups ?? {}),
362	    updatePrompt: ({ cfg, accountId }) =>
363	      Boolean(resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).config.groups),
364	    setPolicy: ({ cfg, accountId, policy }) =>
365	      setIrcGroupAccess(cfg as CoreConfig, accountId, policy, [], normalizeGroupEntry),
366	    resolveAllowlist: async ({ entries }) =>
367	      [...new Set(entries.map((entry) => normalizeGroupEntry(entry)).filter(Boolean))] as string[],
368	    applyAllowlist: ({ cfg, accountId, resolved }) =>
369	      setIrcGroupAccess(
370	        cfg as CoreConfig,
371	        accountId,
372	        "allowlist",
373	        resolved as string[],
374	        normalizeGroupEntry,
375	      ),
376	  },
377	  allowFrom: createAllowFromSection({
378	    helpTitle: "IRC allowlist",
379	    helpLines: [
380	      "Allowlist IRC DMs by sender.",
381	      "Examples:",
382	      "- alice",
383	      "- alice!ident@example.org",
384	      "Multiple entries: comma-separated.",
385	    ],
386	    message: "IRC allowFrom (nick or nick!user@host)",
387	    placeholder: "alice, bob!ident@example.org",
388	    invalidWithoutCredentialNote: "Use an IRC nick or nick!user@host entry.",
389	    parseId: (raw) => {
390	      const normalized = normalizeIrcAllowEntry(raw);
391	      return normalized || null;
392	    },
393	    apply: async ({ cfg, allowFrom }) => setIrcAllowFrom(cfg as CoreConfig, allowFrom),
394	  }),
395	  finalize: async ({ cfg, accountId, prompter }) => {
396	    let next = cfg as CoreConfig;
397	
398	    const resolvedAfterGroups = resolveIrcAccount({ cfg: next, accountId });
399	    if (resolvedAfterGroups.config.groupPolicy === "allowlist") {
400	      const groupKeys = Object.keys(resolvedAfterGroups.config.groups ?? {});
401	      if (groupKeys.length > 0) {
402	        const wantsMentions = await prompter.confirm({
403	          message: "Require @mention to reply in IRC channels?",
404	          initialValue: true,
405	        });
406	        if (!wantsMentions) {
407	          const groups = resolvedAfterGroups.config.groups ?? {};
408	          const patched = Object.fromEntries(
409	            Object.entries(groups).map(([key, value]) => [
410	              key,
411	              { ...value, requireMention: false },
412	            ]),
413	          );
414	          next = updateIrcAccountConfig(next, accountId, { groups: patched });
415	        }
416	      }
417	    }
418	
419	    next = await promptIrcNickServConfig({
420	      cfg: next,
421	      prompter,
422	      accountId,
423	    });
424	    return { cfg: next };
425	  },
426	  completionNote: {
427	    title: "IRC next steps",
428	    lines: [
429	      "Next: restart gateway and verify status.",
430	      "Command: openclaw channels status --probe",
431	      `Docs: ${formatDocsLink("/channels/irc", "channels/irc")}`,
432	    ],
433	  },
434	  dmPolicy: ircDmPolicy,
435	  disable: (cfg) => setSetupChannelEnabled(cfg, channel, false),
436	};
437	
438	export { ircSetupAdapter };
