import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
};

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

/**
 * Send a message to a PulseBoard target (board or user).
 * Stub implementation: logs the message instead of making real network calls.
 */
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const normalized = normalizePulseBoardMessagingTarget(to);
  if (!normalized) {
    throw new Error(`invalid PulseBoard target: ${to}`);
  }

  const messageId = crypto.randomUUID();

  // Stub: log outbound message instead of sending over the network
  const runtime = getPulseBoardRuntime();
  runtime.log?.(
    `[pulseboard] outbound → ${normalized}: ${text.slice(0, 100)}${text.length > 100 ? "..." : ""}`,
  );

  return { messageId, target: normalized };
}

