import { runStoppablePassiveMonitor } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseBoardAccount } from "./accounts.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";
import type { RuntimeEnv } from "../runtime-api.js";

export type PulseBoardMonitorOptions = {
  accountId: string;
  config: CoreConfig;
  runtime: RuntimeEnv;
  abortSignal: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
};

const HEARTBEAT_INTERVAL_MS = 30_000;

/**
 * Connection monitor loop for PulseBoard.
 * Stub implementation: simulates a polling-based connection with heartbeats.
 */
export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const account = resolvePulseBoardAccount({
    cfg: opts.config,
    accountId: opts.accountId,
  });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need host, username, and apiKey).`,
    );
  }

  opts.runtime.log?.(
    `[pulseboard] connected to ${account.host} as ${account.username}`,
  );

  // Join configured boards
  const boards = account.config.boards ?? [];
  if (boards.length > 0) {
    opts.runtime.log?.(
      `[pulseboard] joined boards: ${boards.join(", ")}`,
    );
  }

  // Set up heartbeat polling
  const heartbeatTimer = setInterval(() => {
    if (opts.abortSignal.aborted) {
      return;
    }
    opts.runtime.log?.("[pulseboard] heartbeat");
  }, HEARTBEAT_INTERVAL_MS);

  const stop = () => {
    clearInterval(heartbeatTimer);
    opts.runtime.log?.("[pulseboard] disconnected");
  };

  // Clean up on abort
  opts.abortSignal.addEventListener("abort", stop, { once: true });

  return { stop };
}

