import { describe, expect, it } from "vitest";
import {
  isBoardTarget,
  looksLikePulseBoardTargetId,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardAllowlist,
  normalizePulseBoardMessagingTarget,
  resolvePulseBoardAllowlistMatch,
} from "./normalize.js";
import type { PulseBoardInboundMessage } from "./types.js";

function makeMessage(overrides: Partial<PulseBoardInboundMessage> = {}): PulseBoardInboundMessage {
  return {
    messageId: "msg-1",
    target: "alice",
    senderUsername: "alice",
    text: "hello",
    timestamp: Date.now(),
    isGroup: false,
    ...overrides,
  };
}

describe("isBoardTarget", () => {
  it("returns true for board targets", () => {
    expect(isBoardTarget("b/general")).toBe(true);
    expect(isBoardTarget("b/ops")).toBe(true);
  });

  it("returns false for user targets", () => {
    expect(isBoardTarget("alice")).toBe(false);
    expect(isBoardTarget("")).toBe(false);
  });
});

describe("normalizePulseBoardMessagingTarget", () => {
  it("normalizes board: prefix to b/ prefix", () => {
    expect(normalizePulseBoardMessagingTarget("board:general")).toBe("b/general");
    expect(normalizePulseBoardMessagingTarget("board:ops")).toBe("b/ops");
  });

  it("strips pulseboard: prefix", () => {
    expect(normalizePulseBoardMessagingTarget("pulseboard:board:general")).toBe("b/general");
    expect(normalizePulseBoardMessagingTarget("pulseboard:alice")).toBe("alice");
  });

  it("strips user: prefix", () => {
    expect(normalizePulseBoardMessagingTarget("user:alice")).toBe("alice");
    expect(normalizePulseBoardMessagingTarget("pulseboard:user:bob")).toBe("bob");
  });

  it("passes through plain targets", () => {
    expect(normalizePulseBoardMessagingTarget("b/general")).toBe("b/general");
    expect(normalizePulseBoardMessagingTarget("alice")).toBe("alice");
  });

  it("returns undefined for empty or invalid targets", () => {
    expect(normalizePulseBoardMessagingTarget("")).toBeUndefined();
    expect(normalizePulseBoardMessagingTarget("   ")).toBeUndefined();
    expect(normalizePulseBoardMessagingTarget("has space")).toBeUndefined();
  });
});

describe("looksLikePulseBoardTargetId", () => {
  it("accepts valid target ids", () => {
    expect(looksLikePulseBoardTargetId("alice")).toBe(true);
    expect(looksLikePulseBoardTargetId("b/general")).toBe(true);
  });

  it("rejects empty and whitespace targets", () => {
    expect(looksLikePulseBoardTargetId("")).toBe(false);
    expect(looksLikePulseBoardTargetId("  ")).toBe(false);
    expect(looksLikePulseBoardTargetId("has space")).toBe(false);
  });
});

describe("normalizePulseBoardAllowEntry", () => {
  it("lowercases and trims", () => {
    expect(normalizePulseBoardAllowEntry("Alice")).toBe("alice");
    expect(normalizePulseBoardAllowEntry("  Bob  ")).toBe("bob");
  });

  it("strips pulseboard: prefix", () => {
    expect(normalizePulseBoardAllowEntry("pulseboard:alice")).toBe("alice");
  });

  it("strips user: prefix", () => {
    expect(normalizePulseBoardAllowEntry("user:alice")).toBe("alice");
  });

  it("returns empty for blank input", () => {
    expect(normalizePulseBoardAllowEntry("")).toBe("");
    expect(normalizePulseBoardAllowEntry("   ")).toBe("");
  });
});

describe("normalizePulseBoardAllowlist", () => {
  it("normalizes entries and filters empties", () => {
    expect(normalizePulseBoardAllowlist(["Alice", "  ", "BOB"])).toEqual(["alice", "bob"]);
  });

  it("handles undefined", () => {
    expect(normalizePulseBoardAllowlist(undefined)).toEqual([]);
  });
});

describe("resolvePulseBoardAllowlistMatch", () => {
  it("matches wildcard", () => {
    const result = resolvePulseBoardAllowlistMatch({
      allowFrom: ["*"],
      message: makeMessage(),
    });
    expect(result.allowed).toBe(true);
    expect(result.source).toBe("wildcard");
  });

  it("matches exact username", () => {
    const result = resolvePulseBoardAllowlistMatch({
      allowFrom: ["alice", "bob"],
      message: makeMessage({ senderUsername: "alice" }),
    });
    expect(result.allowed).toBe(true);
    expect(result.source).toBe("alice");
  });

  it("returns not allowed when no match", () => {
    const result = resolvePulseBoardAllowlistMatch({
      allowFrom: ["bob"],
      message: makeMessage({ senderUsername: "alice" }),
    });
    expect(result.allowed).toBe(false);
  });

  it("matches case-insensitively", () => {
    const result = resolvePulseBoardAllowlistMatch({
      allowFrom: ["Alice"],
      message: makeMessage({ senderUsername: "alice" }),
    });
    expect(result.allowed).toBe(true);
  });
});

