import { describe, expect, it } from "vitest";
import { chunkTextForOutbound } from "./chunking.js";

describe("chunkTextForOutbound", () => {
  it("returns single chunk for short text", () => {
    const result = chunkTextForOutbound("hello world", 4000);
    expect(result).toEqual(["hello world"]);
  });

  it("does not chunk text at exactly the limit", () => {
    const text = "a".repeat(4000);
    const result = chunkTextForOutbound(text, 4000);
    expect(result).toEqual([text]);
  });

  it("breaks at newlines when possible", () => {
    const line1 = "a".repeat(50);
    const line2 = "b".repeat(50);
    const text = `${line1}\n${line2}`;
    const result = chunkTextForOutbound(text, 60);
    expect(result).toEqual([line1, line2]);
  });

  it("breaks at spaces when no newlines available", () => {
    const text = "word ".repeat(20).trim(); // ~100 chars
    const result = chunkTextForOutbound(text, 30);
    expect(result.length).toBeGreaterThan(1);
    for (const chunk of result) {
      expect(chunk.length).toBeLessThanOrEqual(30);
    }
  });

  it("hard-breaks at limit when no natural break point", () => {
    const text = "a".repeat(100);
    const result = chunkTextForOutbound(text, 30);
    expect(result.length).toBe(4); // 30 + 30 + 30 + 10
    expect(result[0]).toBe("a".repeat(30));
    expect(result[3]).toBe("a".repeat(10));
  });

  it("handles the 4000-char PulseBoard limit", () => {
    const text = "x".repeat(8500);
    const result = chunkTextForOutbound(text, 4000);
    expect(result.length).toBe(3); // 4000 + 4000 + 500
    expect(result[0]?.length).toBe(4000);
    expect(result[1]?.length).toBe(4000);
    expect(result[2]?.length).toBe(500);
  });
});

