import { afterEach, beforeEach, describe, expect, it } from "vitest";
import {
  listPulseBoardAccountIds,
  resolvePulseBoardAccount,
  type ResolvedPulseBoardAccount,
} from "./accounts.js";
import type { CoreConfig } from "./types.js";

function makeConfig(overrides: Partial<CoreConfig["channels"]> = {}): CoreConfig {
  return {
    channels: {
      ...overrides,
    },
  } as CoreConfig;
}

describe("resolvePulseBoardAccount", () => {
  const savedEnv: Record<string, string | undefined> = {};

  beforeEach(() => {
    for (const key of ["PULSEBOARD_HOST", "PULSEBOARD_API_KEY", "PULSEBOARD_USERNAME", "PULSEBOARD_BOARDS"]) {
      savedEnv[key] = process.env[key];
      delete process.env[key];
    }
  });

  afterEach(() => {
    for (const [key, value] of Object.entries(savedEnv)) {
      if (value === undefined) {
        delete process.env[key];
      } else {
        process.env[key] = value;
      }
    }
  });

  it("returns configured when host, username, and apiKey are present", () => {
    const cfg = makeConfig({
      pulseboard: {
        host: "https://api.pulseboard.example.com",
        username: "clawbot",
        apiKey: "test-key-123",
      },
    });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(true);
    expect(account.host).toBe("https://api.pulseboard.example.com");
    expect(account.username).toBe("clawbot");
    expect(account.apiKey).toBe("test-key-123");
    expect(account.apiKeySource).toBe("config");
  });

  it("returns unconfigured when host is missing", () => {
    const cfg = makeConfig({
      pulseboard: {
        username: "clawbot",
        apiKey: "test-key-123",
      },
    });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(false);
  });

  it("returns unconfigured when apiKey is missing", () => {
    const cfg = makeConfig({
      pulseboard: {
        host: "https://api.pulseboard.example.com",
        username: "clawbot",
      },
    });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(false);
  });

  it("falls back to environment variables for default account", () => {
    process.env.PULSEBOARD_HOST = "https://env.pulseboard.example.com";
    process.env.PULSEBOARD_USERNAME = "envbot";
    process.env.PULSEBOARD_API_KEY = "env-key-456";

    const cfg = makeConfig({});
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(true);
    expect(account.host).toBe("https://env.pulseboard.example.com");
    expect(account.username).toBe("envbot");
    expect(account.apiKey).toBe("env-key-456");
    expect(account.apiKeySource).toBe("env");
  });

  it("does not use env vars for named accounts", () => {
    process.env.PULSEBOARD_HOST = "https://env.pulseboard.example.com";
    process.env.PULSEBOARD_API_KEY = "env-key-456";
    process.env.PULSEBOARD_USERNAME = "envbot";

    const cfg = makeConfig({
      pulseboard: {
        accounts: {
          secondary: {},
        },
      },
    });
    const account = resolvePulseBoardAccount({ cfg, accountId: "secondary" });
    expect(account.configured).toBe(false);
    expect(account.host).toBe("");
  });

  it("reads boards from env var PULSEBOARD_BOARDS", () => {
    process.env.PULSEBOARD_HOST = "https://api.pulseboard.example.com";
    process.env.PULSEBOARD_USERNAME = "clawbot";
    process.env.PULSEBOARD_API_KEY = "test-key";
    process.env.PULSEBOARD_BOARDS = "b/general,b/ops";

    const cfg = makeConfig({});
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.config.boards).toEqual(["b/general", "b/ops"]);
  });

  it("marks account as enabled by default", () => {
    const cfg = makeConfig({
      pulseboard: {
        host: "https://api.pulseboard.example.com",
        username: "clawbot",
        apiKey: "key",
      },
    });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.enabled).toBe(true);
  });

  it("respects enabled=false on account", () => {
    const cfg = makeConfig({
      pulseboard: {
        host: "https://api.pulseboard.example.com",
        username: "clawbot",
        apiKey: "key",
        enabled: false,
      },
    });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.enabled).toBe(false);
  });
});

describe("listPulseBoardAccountIds", () => {
  it("returns default when no accounts configured", () => {
    const cfg = makeConfig({
      pulseboard: {
        host: "https://api.pulseboard.example.com",
      },
    });
    const ids = listPulseBoardAccountIds(cfg);
    expect(ids).toContain("default");
  });

  it("includes named accounts", () => {
    const cfg = makeConfig({
      pulseboard: {
        accounts: {
          primary: { host: "https://one.example.com" },
          secondary: { host: "https://two.example.com" },
        },
      },
    });
    const ids = listPulseBoardAccountIds(cfg);
    expect(ids).toContain("default");
    expect(ids).toContain("primary");
    expect(ids).toContain("secondary");
  });
});

