import { describe, expect, it } from "vitest";
import { PulseBoardConfigSchema } from "./config-schema.js";

describe("PulseBoardConfigSchema", () => {
  it("accepts a valid minimal config", () => {
    const result = PulseBoardConfigSchema.safeParse({
      host: "https://api.pulseboard.example.com",
      username: "clawbot",
      apiKey: "test-key",
    });
    expect(result.success).toBe(true);
  });

  it("accepts an empty config", () => {
    const result = PulseBoardConfigSchema.safeParse({});
    expect(result.success).toBe(true);
  });

  it("accepts config with boards", () => {
    const result = PulseBoardConfigSchema.safeParse({
      host: "https://api.pulseboard.example.com",
      username: "clawbot",
      apiKey: "test-key",
      boards: ["b/general", "b/ops"],
    });
    expect(result.success).toBe(true);
  });

  it("accepts config with groups", () => {
    const result = PulseBoardConfigSchema.safeParse({
      host: "https://api.pulseboard.example.com",
      username: "clawbot",
      apiKey: "test-key",
      groups: {
        "b/general": { requireMention: false },
        "*": { requireMention: true },
      },
    });
    expect(result.success).toBe(true);
  });

  it("accepts config with accounts", () => {
    const result = PulseBoardConfigSchema.safeParse({
      defaultAccount: "primary",
      accounts: {
        primary: {
          host: "https://one.example.com",
          username: "bot1",
          apiKey: "key1",
        },
      },
    });
    expect(result.success).toBe(true);
  });

  it("rejects unknown properties (strict mode)", () => {
    const result = PulseBoardConfigSchema.safeParse({
      unknownField: "value",
    });
    expect(result.success).toBe(false);
  });

  it("rejects dmPolicy=open without wildcard allowFrom", () => {
    const result = PulseBoardConfigSchema.safeParse({
      dmPolicy: "open",
      allowFrom: ["alice"],
    });
    expect(result.success).toBe(false);
    if (!result.success) {
      const messages = result.error.issues.map((issue) => issue.message);
      expect(messages.some((msg) => msg.includes("open"))).toBe(true);
    }
  });

  it("accepts dmPolicy=open with wildcard allowFrom", () => {
    const result = PulseBoardConfigSchema.safeParse({
      dmPolicy: "open",
      allowFrom: ["*"],
    });
    expect(result.success).toBe(true);
  });

  it("defaults dmPolicy to pairing", () => {
    const result = PulseBoardConfigSchema.safeParse({});
    expect(result.success).toBe(true);
    if (result.success) {
      expect(result.data.dmPolicy).toBe("pairing");
    }
  });

  it("defaults groupPolicy to allowlist", () => {
    const result = PulseBoardConfigSchema.safeParse({});
    expect(result.success).toBe(true);
    if (result.success) {
      expect(result.data.groupPolicy).toBe("allowlist");
    }
  });
});

